import React from "react";
import { Link } from "react-router-dom";

function Home() {
  return (
    <div>
      <h1>Welcome</h1>

      <p>Go to register page:</p>

      <Link to="/register">
        <button>Register</button>
      </Link>
    </div>
  );
}

export default Home;
